  1	import * as React from 'react';
  2	import {
  3	  StorageClusterKind,
  4	  StorageClusterModel,
  5	  getName,
  6	  getNamespace,
  7	  useCustomTranslation,
  8	} from '@odf/shared';
  9	import { LoadingInline } from '@odf/shared/generic/Loading';
 10	import { ModalBody, ModalFooter, ModalHeader } from '@odf/shared/modals/Modal';
 11	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 12	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 13	import { useSelector } from 'react-redux';
 14	import { compose } from 'redux';
 15	import {
 16	  Alert,
 17	  Button,
 18	  Flex,
 19	  FlexItem,
 20	  Modal,
 21	  ModalVariant,
 22	  Text,
 23	  TextVariants,
 24	} from '@patternfly/react-core';
 25	import { useSafeK8sGet } from '../../hooks';
 26	import { getODFSystemFlags } from '../../redux';
 27	
 28	const patch = [
 29	  {
 30	    op: 'replace',
 31	    path: '/spec/managedResources/cephCluster/monCount',
 32	    value: 5,
 33	  },
 34	];
 35	
 36	const getStorageClusterName = (store: ReturnType<typeof getODFSystemFlags>) =>
 37	  Object.entries(store.systemFlags).find(([, flags]) => flags.isInternalMode);
 38	
 39	const getMonitorCount = (cluster: StorageClusterKind) =>
 40	  cluster?.status?.currentMonCount;
 41	
 42	const LowMonAlertModal: ModalComponent = ({ closeModal }) => {
 43	  const [namespace, clusterFlags] = useSelector(
 44	    compose(getStorageClusterName, getODFSystemFlags)
 45	  );
 46	  const { t } = useCustomTranslation();
 47	
 48	  const [errorMessage, setErrorMessage] = React.useState('');
 49	  const [inProgress, setProgress] = React.useState(false);
 50	
 51	  // ToDo (epic 4422) (bipuladh): Update it to use information from the alert.
 52	  const [storageCluster, storageClusterLoaded, storageCluserLoadError] =
 53	    useSafeK8sGet<StorageClusterKind>(
 54	      StorageClusterModel,
 55	      clusterFlags.ocsClusterName,
 56	      namespace
 57	    );
 58	
 59	  const failureDomains = storageCluster?.status?.failureDomainValues?.length;
 60	  const Header = <ModalHeader>{t('Configure Ceph Monitor')}</ModalHeader>;
 61	
 62	  const monitorCount = getMonitorCount(storageCluster);
 63	
 64	  const onSubmit = () => {
 65	    setProgress(true);
 66	    k8sPatch({
 67	      model: StorageClusterModel,
 68	      resource: {
 69	        metadata: {
 70	          name: getName(storageCluster),
 71	          namespace: getNamespace(storageCluster),
 72	        },
 73	      },
 74	      data: patch,
 75	    })
 76	      .then(() => {
 77	        setProgress(false);
 78	        closeModal();
 79	      })
 80	      .catch((err) => {
 81	        setProgress(false);
 82	        setErrorMessage(err);
 83	      });
 84	  };
 85	
 86	  return (
 87	    <Modal
 88	      onClose={closeModal}
 89	      isOpen={true}
 90	      variant={ModalVariant.small}
 91	      header={Header}
 92	    >
 93	      <ModalBody>
 94	        <Flex
 95	          direction={{ default: 'column' }}
 96	          spaceItems={{ default: 'spaceItemsXl' }}
 97	        >
 98	          <FlexItem>
 99	            {t(
100	              'To enhance cluster resilience, align Ceph Monitors with the available node failure domains.'
101	            )}
102	          </FlexItem>
103	          <FlexItem>
104	            <Flex
105	              direction={{ default: 'column' }}
106	              spaceItems={{ default: 'spaceItemsNone' }}
107	            >
108	              <FlexItem>
109	                {storageClusterLoaded ? (
110	                  t('Node failure domains: {{failureDomains}}', {
111	                    failureDomains,
112	                  })
113	                ) : (
114	                  <LoadingInline />
115	                )}
116	              </FlexItem>
117	              <FlexItem>
118	                {storageClusterLoaded ? (
119	                  t('Ceph Monitor count: {{monitorCount}}', { monitorCount })
120	                ) : (
121	                  <LoadingInline />
122	                )}
123	              </FlexItem>
124	            </Flex>
125	          </FlexItem>
126	          <FlexItem>
127	            <Text component={TextVariants.h6}>
128	              {t('Recommended Ceph Monitor count: 5')}
129	            </Text>
130	          </FlexItem>
131	        </Flex>
132	        {!!errorMessage && (
133	          <Alert isInline variant="danger" title={t('An error occurred')}>
134	            {(errorMessage as any)?.message || errorMessage}
135	          </Alert>
136	        )}
137	      </ModalBody>
138	      <ModalFooter>
139	        <Button
140	          key="cancel"
141	          variant="secondary"
142	          onClick={closeModal}
143	          data-test-id="modal-cancel-action"
144	        >
145	          {t('Cancel')}
146	        </Button>
147	        {!inProgress && storageClusterLoaded ? (
148	          <Button
149	            key="Add"
150	            data-test="modal-submit-action"
151	            data-test-id="confirm-action"
152	            variant="primary"
153	            onClick={onSubmit}
154	            disabled={!!storageCluserLoadError}
155	          >
156	            {t('Update count')}
157	          </Button>
158	        ) : (
159	          <LoadingInline />
160	        )}
161	      </ModalFooter>
162	    </Modal>
163	  );
164	};
165	
166	export const launchLowMonAlertModal = async (_alert, launchModal) => {
167	  try {
168	    launchModal(LowMonAlertModal, { isOpen: true });
169	  } catch (e) {
170	    // eslint-disable-next-line no-console
171	    console.error('Error launching modal', e);
172	  }
173	};

